def write_placeholders(slug, data):
    os.makedirs(os.path.join(DIR, '_placeholders'), exist_ok=True)
    lines = []
    for k, v in data.items():
        lines.append(f'@@@{k}@@@\n{v}\n')
    with open(os.path.join(DIR, '_placeholders', f'{slug}.txt'), 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines))
    print(f'wrote {slug}.txt ({len(data)} segments)')

write_placeholders('1', LP1)
write_placeholders('2', LP2)
write_placeholders('3', LP3)
write_placeholders('4', LP4)
print('Part1 done (LP1-LP4)')
